func (this *HtxCore) ParseOrderStatus(status any) any {
	var statuses any = map[string]any{
		"partial-filled":   "open",
		"partial-canceled": "canceled",
		"filled":           "closed",
		"canceled":         "canceled",
		"submitted":        "open",
		"created":          "open",
		"1":                "open",
		"2":                "open",
		"3":                "open",
		"4":                "open",
		"5":                "canceled",
		"6":                "closed",
		"7":                "canceled",
		"11":               "canceling",
	}
	return this.SafeString(statuses, status, status)
}
