	//
	// stop-loss and take-profit: fetchOrders
	//
	//     {
	//         "contract_type": "swap",
	//         "business_type": "swap",
	//         "pair": "BTC-USDT",
	//         "symbol": "BTC",
	//         "contract_code": "BTC-USDT",
	//         "margin_mode": "cross",
